from __future__ import annotations
import json
from pathlib import Path

HTML=Path('docs/index.html');DATA=Path('data/dashboard/wnba_model_picks_ledger.json')
CSS=r'''<style id="v4-model-picks-ledger-style">.plGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px}.plCard{border:1px solid #21314b;border-radius:14px;padding:14px;background:#08101c}.plValue{font-size:26px;font-weight:950}.plTableWrap{overflow:auto;border:1px solid #1e2a43;border-radius:14px;margin-top:12px}.plTable{min-width:980px;width:100%;border-collapse:collapse}.plTable th,.plTable td{padding:8px;border-bottom:1px solid #1d2b42;text-align:left;font-size:12px}.plWin{color:#00e39b}.plLoss{color:#ff6b7c}.plPush{color:#ffd166}.plPending{color:#8fa0bd}.plSearch{width:100%;max-width:480px;border:1px solid #263854;background:#08101c;color:#e7eefc;border-radius:10px;padding:10px 12px;margin:12px 0}.plWindow{display:flex;gap:8px;flex-wrap:wrap;margin:10px 0}.plChip{border:1px solid #263854;border-radius:999px;padding:7px 10px;font-size:11px}.plMonoSmall{font-size:10px;color:#8fa0bd}</style>'''
SCRIPT=r'''<script id="v4-model-picks-ledger-script">(function(){window.modelPicksLedger=function(){const p=DATA.model_picks_ledger||{},s=p.summary||{},rows=Array.isArray(p.recent_picks)?p.recent_picks:[],windows=Array.isArray(p.windows)?p.windows:[];const windowHtml=windows.map(w=>`<span class="plChip mono">${E(w.days)}D · ${E(w.wins||0)}-${E(w.losses||0)} · ROI ${w.roi==null?'—':(Number(w.roi)*100).toFixed(1)+'%'}</span>`).join('');const cards=`<div class="plGrid"><div class="plCard"><div class="small">Archived Picks</div><div class="plValue mono">${E(s.picks||0)}</div></div><div class="plCard"><div class="small">Record</div><div class="plValue mono">${E(s.wins||0)}-${E(s.losses||0)}-${E(s.pushes||0)}</div></div><div class="plCard"><div class="small">Win Rate</div><div class="plValue mono">${s.win_rate==null?'—':(Number(s.win_rate)*100).toFixed(1)+'%'}</div></div><div class="plCard"><div class="small">Flat-Unit ROI</div><div class="plValue mono">${s.roi==null?'—':(Number(s.roi)*100).toFixed(1)+'%'}</div></div><div class="plCard"><div class="small">Average CLV</div><div class="plValue mono">${s.average_clv==null?'—':E(s.average_clv)}</div></div><div class="plCard"><div class="small">Projection MAE</div><div class="plValue mono">${s.mae==null?'—':E(s.mae)}</div></div></div>`;const tableRows=rows.map((r,i)=>{const cls=r.outcome==='WIN'?'plWin':r.outcome==='LOSS'?'plLoss':r.outcome==='PUSH'?'plPush':'plPending';return `<tr class="plPickRow"><td>${E(r.date)}</td><td><b>${E(r.player||'—')}</b><div class="plMonoSmall mono">${E(r.game||'')}</div></td><td>${E(r.stat)} ${E(r.side)} ${E(r.line)}</td><td>${E(r.odds||'—')}</td><td>${r.projection==null?'—':E(r.projection)}</td><td>${r.hit_probability==null?'—':(Number(r.hit_probability)*100).toFixed(1)+'%'}</td><td>${r.line_clv==null?'—':E(r.line_clv)}</td><td class="${cls}">${E(r.outcome)}</td><td>${r.actual==null?'—':E(r.actual)}</td><td>${r.profit_loss==null?'—':E(r.profit_loss)}</td><td>${E(r.model_version||'—')}</td></tr>`}).join('');return `<div class="section"><h2 class="mono">Model Picks History</h2><div class="small mono">Automated model evaluation only. No personal wagers or bankroll data are stored.</div>${cards}<div class="plWindow">${windowHtml}</div><input class="plSearch" id="plSearch" placeholder="Search player, stat, game, sportsbook, or model version" oninput="filterModelPicks(this.value)"><div class="plTableWrap"><table class="plTable"><thead><tr><th>Date</th><th>Player / Game</th><th>Pick</th><th>Odds</th><th>Proj</th><th>Prob</th><th>CLV</th><th>Result</th><th>Actual</th><th>P/L</th><th>Version</th></tr></thead><tbody id="plRows">${tableRows||'<tr><td colspan="11">No archived model picks yet.</td></tr>'}</tbody></table></div></div>`};window.filterModelPicks=function(q){const term=String(q||'').toLowerCase();document.querySelectorAll('.plPickRow').forEach(row=>row.style.display=row.textContent.toLowerCase().includes(term)?'':'none')};const previous=window.marketIntelligence;window.marketIntelligence=function(){const base=typeof previous==='function'?previous():'';return base+window.modelPicksLedger()};})();</script>'''

def replace_block(html,start,end,replacement):
    i=html.find(start)
    if i<0:return html
    j=html.find(end,i)
    if j<0:return html
    return html[:i]+replacement.strip()+html[j+len(end):]

def main():
    if not HTML.exists():raise SystemExit('docs/index.html missing')
    try:payload=json.load(DATA.open(encoding='utf-8')) if DATA.exists() else {}
    except Exception:payload={}
    html=HTML.read_text(encoding='utf-8');data=f'<script id="v4-model-picks-ledger-data">DATA.model_picks_ledger={json.dumps(payload,separators=(",",":"),ensure_ascii=False)};</script>'
    html=replace_block(html,'<script id="v4-model-picks-ledger-data">','</script>',data) if 'id="v4-model-picks-ledger-data"' in html else html.replace('</body>',data+'</body>')
    html=replace_block(html,'<style id="v4-model-picks-ledger-style">','</style>',CSS) if 'id="v4-model-picks-ledger-style"' in html else html.replace('</head>',CSS+'</head>')
    html=replace_block(html,'<script id="v4-model-picks-ledger-script">','</script>',SCRIPT) if 'id="v4-model-picks-ledger-script"' in html else html.replace('</body>',SCRIPT+'</body>')
    HTML.write_text(html,encoding='utf-8');print('Model Picks History added to Performance Center')
if __name__=='__main__':main()
